from dataclasses import dataclass, field
from typing import Callable


# ── Tipos ────────────────────────────────────────────────────────────────────

@dataclass
class AgentState:
    """Estado completo del agente en cada iteración."""
    objective: str
    steps: list[dict] = field(default_factory=list)
    final_answer: str | None = None

    def add_step(self, thought: str, action: str, observation: str):
        self.steps.append({
            'thought': thought,
            'action': action,
            'observation': observation,
        })


# ── Herramientas disponibles ─────────────────────────────────────────────────

def tool_buscar_precio(producto: str) -> str:
    """Simula búsqueda de precio en base de datos."""
    precios = {
        'laptop': '$1200',
        'monitor': '$350',
        'teclado': '$85',
        'mouse': '$45',
    }
    return precios.get(producto.lower(), f'Producto "{producto}" no encontrado')


def tool_calcular_total(*args) -> str:
    """Suma una lista de precios con formato $N."""
    try:
        total = sum(float(p.replace('$', '').replace(',', '')) for p in args)
        return f'${total:.2f}'
    except ValueError as e:
        return f'Error al calcular: {e}'


TOOLS: dict[str, Callable] = {
    'buscar_precio': tool_buscar_precio,
    'calcular_total': tool_calcular_total,
}


# ── Motor de razonamiento (simulado) ─────────────────────────────────────────

def reason(state: AgentState) -> tuple[str, str]:
    """
    Decide la próxima acción basándose en el estado actual.
    En producción, esto es un LLM call.
    Retorna (thought, action_string).
    """
    steps = state.steps
    objective = state.objective

    # Sin pasos: buscar el primer producto
    if not steps:
        producto = objective.split('y')[0].strip().replace('¿Cuánto cuesta ', '').replace('?', '').strip()
        return (
            f'Necesito encontrar el precio de "{producto}" primero.',
            f'buscar_precio("{producto}")'
        )

    last_obs = steps[-1]['observation']

    # Si tenemos un precio y el objetivo pide dos productos, buscar el segundo
    if '$' in last_obs and 'y' in objective and len(steps) == 1:
        segundo = objective.split('y')[1].strip().replace('?', '').strip()
        return (
            f'Tengo el primer precio ({last_obs}). Busco el segundo producto.',
            f'buscar_precio("{segundo}")'
        )

    # Si tenemos dos precios, calcular el total
    precios = [s['observation'] for s in steps if '$' in s.get('observation', '')]
    if len(precios) >= 2 and 'calcular' not in str([s['action'] for s in steps]):
        return (
            f'Tengo ambos precios: {precios}. Calculo el total.',
            f'calcular_total("{precios[0]}", "{precios[1]}")'
        )

    # Tenemos todo — respuesta final
    total = last_obs
    return (
        f'El total calculado es {total}. Tengo suficiente información.',
        f'FINAL_ANSWER: El costo total es {total}'
    )


# ── Executor ─────────────────────────────────────────────────────────────────

def execute(action_str: str) -> str:
    """Parsea y ejecuta la acción indicada por el motor de razonamiento."""
    if action_str.startswith('FINAL_ANSWER:'):
        return action_str  # señal de fin, no es una tool

    # Parsear: nombre_tool("arg1", "arg2")
    tool_name = action_str.split('(')[0].strip()
    args_str = action_str[len(tool_name)+1:-1]  # quitar nombre( y )
    args = [a.strip().strip('"') for a in args_str.split(',') if a.strip()]

    if tool_name not in TOOLS:
        return f'Error: herramienta "{tool_name}" no encontrada'

    return TOOLS[tool_name](*args)


# ── Loop principal ────────────────────────────────────────────────────────────

def run_agent(objective: str, max_steps: int = 6) -> str:
    state = AgentState(objective=objective)
    print(f'Objetivo: {objective}')
    print('-' * 50)

    for step_num in range(1, max_steps + 1):
        thought, action = reason(state)
        print(f'[Paso {step_num}] Razonamiento: {thought}')
        print(f'[Paso {step_num}] Acción: {action}')

        if action.startswith('FINAL_ANSWER:'):
            answer = action.replace('FINAL_ANSWER: ', '')
            state.final_answer = answer
            print(f'[Resultado] {answer}')
            return answer

        observation = execute(action)
        print(f'[Paso {step_num}] Observación: {observation}')
        print()
        state.add_step(thought, action, observation)

    return 'Límite de pasos alcanzado sin respuesta final'


if __name__ == '__main__':
    run_agent('¿Cuánto cuesta laptop y monitor?')
